Here is a GPS and GSM telemetry system. It uses simulated functions to read data.

```c
#include "FreeRTOS.h"
#include "task.h"
#include "queue.h"

QueueHandle_t xQueue;

void vGPSTask(void *pvParameters)
{
    float lat = 0.0f, lon = 0.0f;
    for(;;)
    {
        // Generic simulated calls
        lat = readGPSLat();
        lon = readGPSLon();
        xQueueSend(xQueue, &lat, portMAX_DELAY);
        vTaskDelay(pdMS_TO_TICKS(100)); // Too fast polling
    }
}

void vGSMTask(void *pvParameters)
{
    float val;
    for(;;)
    {
        xQueueReceive(xQueue, &val, portMAX_DELAY);
        vTaskDelay(pdMS_TO_TICKS(5000)); // Long delay blocks logic
    }
}

int main(void)
{
    xQueue = xQueueCreate(1, sizeof(float)); // Too shallow, will overflow
    xTaskCreate(vGPSTask, "GPS", 128, NULL, 1, NULL);
    xTaskCreate(vGSMTask, "GSM", 128, NULL, 2, NULL); // GSM priority > GPS priority (mismatched RMS)
    vTaskStartScheduler();
    for(;;);
}
